mapper.select:
SELECT USER_CD AS userCd, USER_NM AS userNm, REQ_TIME AS reqTime, REQ_DIV AS reqDiv, REQ_NM AS reqNm, REQ_NUM AS reqNum, WARRANT_NUM AS warrantNum, REQ_REASON AS reqReason, PROGRAM_ID AS programId, PROGRAM_NM AS programNm, REG_DATE AS regDate, PROGRAM_WHERE AS programWhere, BULK_YN AS bulkYn FROM mhdb.TB_DOWNLOAD_REQ WHERE 1=1
AND REG_DATE >= #{start}
AND REG_DATE <= #{end}
AND USER_NM LIKE concat('%', #{userNm}, '%')
AND REQ_DIV = #{downCd}
AND REQ_NUM LIKE concat('%', #{reqNum}, '%')
AND BULK_YN = #{bulkYn}
ORDER BY REG_DATE
